# We'll compute approximate ratio with difflib SequenceMatcher ratio across entire hadith text might be small; 
# We'll also search for n-gram windows within hadith text around tokens 'الذنوب', 'تزكي', to find a close phrase.
def normalized_ratio(a,b):
    return difflib.SequenceMatcher(None, normalize(a), normalize(b), autojunk=False).ratio()

